// Filter and format projects for the video commercial
const data = $input.first().json;
const items = data.items || [];

if (items.length === 0) {
  throw new Error('No public projects with photos found');
}

const projects = items.map(item => ({
  id: item.id,
  collectionId: item.collectionId,
  name: item.name,
  author_name: item.expand?.user?.name || item.expand?.user?.username || 'PaintPile Artist',
  cover_photo: item.cover_photo || null,
  photos: item.photos || [],
  description: item.description || ''
}));

return [{ json: { projects } }];

