// Parse the Claude response and extract the script JSON
const response = $input.first().json;
const text = response.content?.[0]?.text || '';

// Extract JSON array from the response
let script;
try {
  script = JSON.parse(text);
} catch {
  // Try to find JSON array in the text
  const match = text.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) {
    script = JSON.parse(match[0]);
  } else {
    throw new Error('Could not parse script from Claude response: ' + text.substring(0, 200));
  }
}

// Get projects from the previous Format Projects node
const projects = $('Format Projects').first().json.projects;

return [{ json: { projects, script } }];

// Upload the generated reel video to a temporary public URL via PocketBase
// For now, log success and pass through for Instagram Reels posting
const reelData = $('Generate Reel (9:16)').first();
const squareData = $('Generate Square (1:1)').first();
const scriptData = $('Parse Script').first().json;

// Build caption from script
const projectNames = scriptData.projects.map(p => p.name).join(', ');
const caption = `🎨 Check out these amazing miniatures on PaintPile!\n\nFeaturing: ${projectNames}\n\nJoin our community at thepaintpile.com\n\n#paintpile #minipainting #warhammer #tabletop #miniatures #painting #hobby`;

return [{
  json: {
    caption,
    projects: scriptData.projects,
    reelGenerated: !!reelData,
    squareGenerated: !!squareData
  }
}];
